/**
 * @name Path traversal in StaticHandlerImpl - sendStatic method
 * @description Finds where HTTP request paths flow to file system operations in StaticHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-path-traversal-precise
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module StaticHandlerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getPath(), getNormalisedPath(), uri() called on RoutingContext
    exists(MethodCall mc |
      mc.getMethod().hasName("getPath") or
      mc.getMethod().hasName("getNormalisedPath") or
      mc.getMethod().hasName("uri") or
      mc.getMethod().hasName("normalizedPath")
    |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor calls 
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") |
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // vertx sendFile calls
    exists(MethodCall mc |
      mc.getMethod().hasName("sendFile") |
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // String canonicalization calls
    exists(MethodCall mc |
      mc.getMethod().hasName("getCanonicalPath") or
      mc.getMethod().hasName("toRealPath")
    |
      node.asExpr() = mc
    )
  }
}

module StaticHandlerFlow = TaintTracking::Global<StaticHandlerConfig>;
import StaticHandlerFlow::PathGraph

from StaticHandlerFlow::PathNode source, StaticHandlerFlow::PathNode sink
where 
  StaticHandlerFlow::flowPath(source, sink) and
  sink.getNode().getEnclosingCallable().getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
select sink.getNode(), source, sink, "Path traversal: HTTP request path flows to file system operation in StaticHandlerImpl."

/**
 * @name Path traversal via String.startsWith containment check in StaticHandler
 * @description Using String.startsWith() for directory containment checks can be bypassed if the path is not properly canonicalized first
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-startswith-traversal
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Model the normalized path method in StaticHandlerImpl
class StaticHandlerImpl extends RefType {
  StaticHandlerImpl() {
    this.hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
  }
}

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: HTTP request URI/path
    exists(MethodCall mc |
      mc.getMethod().hasName("normalizedPath") or
      mc.getMethod().hasName("path") or
      mc.getMethod().hasName("getParam") or
      mc.getMethod().hasName("uri")
    |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: sendFile calls in StaticHandlerImpl
    exists(MethodCall mc |
      mc.getMethod().hasName("sendFile") or
      mc.getMethod().hasName("getFile")
    |
      mc.getEnclosingCallable().getDeclaringType() instanceof StaticHandlerImpl and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal from $@.", source.getNode(), "HTTP request path"

/**
 * @name Path traversal in StaticHandlerImpl via normalized path
 * @description Traces HTTP request path to file system operations in StaticHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-path-traversal-precise
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Identifies the StaticHandlerImpl class
class StaticHandlerImpl extends RefType {
  StaticHandlerImpl() {
    this.hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
  }
}

// Source: HTTP request path/URI methods used in StaticHandlerImpl context
class StaticHandlerHTTPSource extends DataFlow::Node {
  StaticHandlerHTTPSource() {
    // normalizedPath() or path() calls in StaticHandlerImpl methods
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("normalizedPath") or
        mc.getMethod().hasName("path") or
        mc.getMethod().hasName("getPath") or
        mc.getMethod().hasName("normalisedPath")
      ) and
      mc.getEnclosingCallable().getDeclaringType() instanceof StaticHandlerImpl and
      this.asExpr() = mc
    )
  }
}

// Sink: Vertx sendFile or getFile operations
class FileServingSink extends DataFlow::Node {
  FileServingSink() {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("sendFile") or
        mc.getMethod().hasName("getFile") or
        mc.getMethod().hasName("exists") or
        mc.getMethod().hasName("isDirectory")
      ) and
      mc.getEnclosingCallable().getDeclaringType() instanceof StaticHandlerImpl and
      this.asExpr() = mc.getAnArgument()
    )
  }
}

module StaticHandlerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof StaticHandlerHTTPSource
  }

  predicate isSink(DataFlow::Node sink) {
    sink instanceof FileServingSink
  }
}

module StaticHandlerFlow = TaintTracking::Global<StaticHandlerConfig>;
import StaticHandlerFlow::PathGraph

from StaticHandlerFlow::PathNode source, StaticHandlerFlow::PathNode sink
where StaticHandlerFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP request path flows to file serving operation without adequate path traversal prevention."

/**
 * @name Path traversal via StaticHandler cleanPath with URL scheme bypass
 * @description The StaticHandlerImpl uses cleanPath from Utils.java to normalize paths. 
 *              If cleanPath handles protocol prefixes (file:, classpath:) differently than 
 *              the containment check, it may enable path traversal.
 * @kind problem
 * @problem.severity error
 * @id java/static-handler-url-scheme-bypass
 * @tags security
 *       external/cwe/cwe-022
 */

import java

// Find all methods in StaticHandlerImpl
class StaticHandlerImplMethod extends Method {
  StaticHandlerImplMethod() {
    this.getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
  }
}

// Find calls to cleanPath (the path normalization utility)
class CleanPathCall extends MethodCall {
  CleanPathCall() {
    this.getMethod().hasName("cleanPath") and
    this.getEnclosingCallable().(Method).getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
  }
}

// Find calls to sendFile or getFile in StaticHandlerImpl
class FileAccessCall extends MethodCall {
  FileAccessCall() {
    (this.getMethod().hasName("sendFile") or 
     this.getMethod().hasName("getFile") or
     this.getMethod().hasName("sendFileRange")) and
    this.getEnclosingCallable().(Method).getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl")
  }
}

// Find calls to Utils.cleanPath 
class UtilsCleanPathCall extends MethodCall {
  UtilsCleanPathCall() {
    this.getMethod().hasName("cleanPath")
  }
}

from UtilsCleanPathCall call
select call, "Call to cleanPath in " + call.getEnclosingCallable().getName() + " at line " + call.getLocation().getStartLine()
